package consistent

import "testing"

func TestTotalLoadTracksWithinBoundAssignments(t *testing.T) {
	h := NewBoundedLoadHash(8, 100.0)
	nodes := []string{"node-a", "node-b", "node-c"}
	for _, node := range nodes {
		h.Add(node)
	}

	for i, key := range []string{
		"key-0",
		"key-1",
		"key-2",
		"key-3",
		"key-4",
		"key-5",
		"key-6",
		"key-7",
		"key-8",
	} {
		if got := h.Get(key); got == "" {
			t.Fatalf("Get(%q) returned empty node", key)
		}

		assertTotalLoadMatchesSum(t, h, nodes)
		if got, want := h.TotalLoad(), i+1; got != want {
			t.Fatalf("TotalLoad() = %d, want %d", got, want)
		}
	}
}

func TestTotalLoadTracksMixedAssignmentAndRemoval(t *testing.T) {
	h := NewBoundedLoadHash(8, 100.0)
	nodes := []string{"node-a", "node-b", "node-c"}
	for _, node := range nodes {
		h.Add(node)
	}

	assignments := make([]string, 0, 6)
	for _, key := range []string{"key-0", "key-1", "key-2", "key-3", "key-4", "key-5"} {
		node := h.Get(key)
		if node == "" {
			t.Fatalf("Get(%q) returned empty node", key)
		}
		assignments = append(assignments, node)
	}
	assertTotalLoadMatchesSum(t, h, nodes)

	h.Release(assignments[1])
	assertTotalLoadMatchesSum(t, h, nodes)

	if got := h.Get("key-after-release"); got == "" {
		t.Fatal("Get after release returned empty node")
	}
	assertTotalLoadMatchesSum(t, h, nodes)

	h.Remove("node-b")
	nodes = []string{"node-a", "node-c"}
	assertTotalLoadMatchesSum(t, h, nodes)

	if got := h.Get("key-after-remove"); got == "" {
		t.Fatal("Get after remove returned empty node")
	}
	assertTotalLoadMatchesSum(t, h, nodes)
}

func TestTotalLoadTracksWithinBoundAndOverBoundBoundary(t *testing.T) {
	h := NewBoundedLoadHash(1, 1.0)
	nodes := []string{"node-a", "node-b"}
	for _, node := range nodes {
		h.Add(node)
	}

	for _, key := range []string{"key-0", "key-1"} {
		if got := h.Get(key); got == "" {
			t.Fatalf("Get(%q) returned empty node", key)
		}
		assertTotalLoadMatchesSum(t, h, nodes)
	}

	for _, node := range nodes {
		if got := h.Load(node); got != 1 {
			t.Fatalf("Load(%q) = %d, want 1 before over-bound assignment", node, got)
		}
	}
	if got := h.maxLoadPerNode(); got != 1 {
		t.Fatalf("maxLoadPerNode() = %d, want 1 before over-bound assignment", got)
	}

	if got := h.Get("key-2"); got == "" {
		t.Fatal("over-bound Get returned empty node")
	}
	assertTotalLoadMatchesSum(t, h, nodes)

	overBoundLoads := 0
	for _, node := range nodes {
		if h.Load(node) > 1 {
			overBoundLoads++
		}
	}
	if overBoundLoads != 1 {
		t.Fatalf("over-bound assignment should put exactly one node above bound, got %d", overBoundLoads)
	}
}

func assertTotalLoadMatchesSum(t *testing.T, h *BoundedLoadHash, nodes []string) {
	t.Helper()

	sum := 0
	for _, node := range nodes {
		sum += h.Load(node)
	}
	if got := h.TotalLoad(); got != sum {
		t.Fatalf("TotalLoad() = %d, want sum of node loads %d", got, sum)
	}
}

